css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); width: calc(var(--loader-size) * 2.55); min-width: 160px; padding: 14px; border-radius: 22px; background: linear-gradient(145deg, #121827, #0b1020); box-shadow: inset 0 1px #fff2, 0 18px 40px #02061766; overflow: hidden; position: relative; }
.loader::before { content: ""; position: absolute; inset: -45%; background: conic-gradient(from 0deg, transparent, var(--accent), var(--accent-2), transparent 45%); animation: aurora-sweep calc(var(--speed) * 4) linear infinite; opacity: .35; }
.media, .row { position: relative; overflow: hidden; background: #293145; border-radius: 14px; z-index: 1; }
.media { height: calc(var(--loader-size) * .82); margin-bottom: 14px; }
.row { height: 11px; margin-top: 10px; width: 100%; }
.row-lg { width: 82%; }
.row-sm { width: 55%; }
.media::after, .row::after { content: ""; position: absolute; inset: 0; translate: -120% 0; background: linear-gradient(90deg, transparent, #ffffff40, transparent); animation: aurora-line calc(var(--speed) * 1.45) ease-in-out infinite; }
.row:nth-of-type(3)::after { animation-delay: .15s; }
.row:nth-of-type(4)::after { animation-delay: .3s; }
@keyframes aurora-line { to { translate: 120% 0; } }
@keyframes aurora-sweep { to { rotate: 360deg; } }
